#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Function to convert postfix to infix
char* postfixToInfix(char* postfix) {
    int n = strlen(postfix);
    char* stack[n];
    int top = -1;

    for (int i = 0; i < n; i++) {
        char c = postfix[i];

        if (isalnum(c)) {
            stack[++top] = (char*) malloc(2);
            stack[top][0] = c;
            stack[top][1] = '\0';
        } else {
            char* op2 = stack[top--];
            char* op1 = stack[top--];

            char* temp = (char*) malloc(strlen(op1) + strlen(op2) + 3);
            sprintf(temp, "(%s%c%s)", op1, c, op2);

            free(op1);
            free(op2);

            stack[++top] = temp;
        }
    }

    return stack[top];
}

int main() {
    char postfix[] = "AB*C+";
    printf("Infix Expression: %s\n", postfixToInfix(postfix));
    return 0;
}

