#include <iostream>
#include <stack>
#include <string>

// Function to convert postfix to infix
std::string postfixToInfix(std::string postfix) {
    std::stack<std::string> s;
    int n = postfix.size();

    for (int i = 0; i < n; i++) {
        char c = postfix[i];

        if (isalnum(c)) {
            s.push(std::string(1, c));
        } else {
            std::string op2 = s.top(); s.pop();
            std::string op1 = s.top(); s.pop();

            s.push("(" + op1 + c + op2 + ")");
        }
    }

    return s.top();
}

int main() {
    std::string postfix = "AB*C+";
    std::cout << "Infix Expression: " << postfixToInfix(postfix) << std::endl;
    return 0;
}

